            reader.setFeature("http://xml.org/sax/features/external-general-entities", false);
            reader.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            reader.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);

            // Parse with DOM4J
            org.dom4j.Document dom4jDoc = reader.read(configFile);

            // Convert DOM4J Document to W3C DOM Document
            return convertDom4jToW3cDocument(dom4jDoc);

        } catch (Exception e) {
            throw new Exception("Failed to parse XML configuration: " + e.getMessage(), e);
        }
    }

    /**
     * Converts a DOM4J Document to W3C DOM Document.
     * 
     * @param dom4jDoc the DOM4J document
     * @return W3C DOM document
     * @throws Exception if conversion fails
     */
    private Document convertDom4jToW3cDocument(org.dom4j.Document dom4jDoc) throws Exception {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();

        // Apply security settings
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
        factory.setXIncludeAware(false);
        factory.setExpandEntityReferences(false);
        factory.setNamespaceAware(true);

        DocumentBuilder builder = factory.newDocumentBuilder();

        // Convert DOM4J to string and parse back to W3C DOM
        String xmlString = dom4jDoc.asXML();
        return builder.parse(new java.io.ByteArrayInputStream(xmlString.getBytes("UTF-8")));
    }
}
